# ssl_dataset/preprocessed/dataset.py
#
# SSLPreprocessedDataset — ready-to-train numpy arrays.
#
# What this class does:
#   1. Downloads pre-generated .npy files from HuggingFace (once, then cached)
#   2. Loads them directly into numpy arrays — no JSON parsing, no image loading
#   3. Returns the exact splits that were generated by the corrected Colab script
#
# Why pre-generated .npy files instead of generating on-the-fly?
#   - Speed: loading a .npy file takes milliseconds vs parsing thousands of
#     JSON files or reading thousands of images
#   - Reproducibility: the exact same arrays are returned every time,
#     guaranteed to match the thesis results
#   - Simplicity: users who just want to train a model don't need to think
#     about landmark parsing or image loading at all
#
# Output shapes (currently only "lstm" format is available):
#
#   format="lstm"
#     X : (N, 30, 63)   float32 — landmark sequences, direct LSTM input
#     y : (N, 55)       float32 — one-hot encoded class labels
#
# HuggingFace folder structure expected:
#   lstm/X_train.npy, lstm/X_val.npy, lstm/X_test.npy
#   lstm/y_train.npy, lstm/y_val.npy, lstm/y_test.npy

import numpy as np

from .._constants import (
    CLASS_LABELS,
    NUM_CLASSES,
    HF_REPO_PREPROCESSED,
    CACHE_DIR_PREPROCESSED,
)
from .._downloader import download_preprocessed_file

VALID_FORMATS = ("lstm",)
VALID_SPLITS  = ("train", "val", "test")


class SSLPreprocessedDataset:
    """
    Sinhala Sign Language preprocessed dataset — ready to train immediately.

    Downloads pre-split, pre-labelled numpy arrays from HuggingFace.
    No landmark parsing or image loading required — just load and train.

    Parameters
    ----------
    split : str
        Which portion of the dataset to load.
        "train" → 2842 samples
        "val"   → 609 samples
        "test"  → 609 samples
        (Unlike the other sub-libraries, "all" is not supported here
        because the .npy files are stored as separate split files.)

    format : str
        Which preprocessed format to load.
        "lstm" → X shape (N, 30, 63), y shape (N, 55) one-hot

    Examples
    --------
    >>> from ssl_dataset.preprocessed import SSLPreprocessedDataset
    >>>
    >>> # Load training data — ready to pass directly into model.fit()
    >>> ds = SSLPreprocessedDataset(split="train", format="lstm")
    >>> X, y = ds.load()
    >>> print(X.shape)   # (2842, 30, 63)
    >>> print(y.shape)   # (2842, 55)
    >>>
    >>> # Train a model immediately
    >>> model.fit(X, y, validation_data=(X_val, y_val))
    >>>
    >>> # Load all three splits at once
    >>> X_train, y_train = SSLPreprocessedDataset("train").load()
    >>> X_val,   y_val   = SSLPreprocessedDataset("val").load()
    >>> X_test,  y_test  = SSLPreprocessedDataset("test").load()
    """

    def __init__(
        self,
        split: str = "train",
        format: str = "lstm",
    ):
        if split not in VALID_SPLITS:
            raise ValueError(
                f"split must be one of {VALID_SPLITS}, got {split!r}"
            )
        if format not in VALID_FORMATS:
            raise ValueError(
                f"format must be one of {VALID_FORMATS}, got {format!r}"
            )

        self.split  = split
        self.format = format

        # Populated lazily on first call to .load()
        self._X = None
        self._y = None

    # ------------------------------------------------------------------
    # Public API
    # ------------------------------------------------------------------

    def load(self):
        """
        Download (if needed) and load the preprocessed arrays.

        Returns
        -------
        X : np.ndarray
            Feature array.
            "lstm" format → shape (N, 30, 63), dtype float32

        y : np.ndarray
            One-hot encoded label array.
            "lstm" format → shape (N, 55), dtype float32

        Notes
        -----
        Calling load() a second time returns the cached result immediately
        without re-reading any files.
        """
        if self._X is None:
            self._X, self._y = self._load_npy_files()

        return self._X, self._y

    @property
    def class_labels(self) -> dict:
        """Return the full class index → sign label mapping."""
        return CLASS_LABELS

    @property
    def num_classes(self) -> int:
        """Total number of sign classes (55)."""
        return NUM_CLASSES

    @property
    def input_shape(self) -> tuple:
        """
        The input shape expected by the model (excluding batch dimension).

        "lstm" format → (30, 63)

        Example
        -------
        >>> ds = SSLPreprocessedDataset("train")
        >>> model.add(LSTM(128, input_shape=ds.input_shape))
        """
        if self.format == "lstm":
            return (30, 63)

    def __repr__(self) -> str:
        return (
            f"SSLPreprocessedDataset("
            f"split={self.split!r}, "
            f"format={self.format!r})"
        )

    # ------------------------------------------------------------------
    # Internal: loading .npy files
    # ------------------------------------------------------------------

    def _load_npy_files(self):
        """
        Download and load the X and y .npy files for the requested split.

        Remote paths follow the pattern:
            {format}/X_{split}.npy   e.g. "lstm/X_train.npy"
            {format}/y_{split}.npy   e.g. "lstm/y_train.npy"
        """
        x_remote = f"{self.format}/X_{self.split}.npy"
        y_remote = f"{self.format}/y_{self.split}.npy"

        print(f"Loading {x_remote} ...")
        x_path = download_preprocessed_file(x_remote)

        print(f"Loading {y_remote} ...")
        y_path = download_preprocessed_file(y_remote)

        X = np.load(str(x_path))
        y = np.load(str(y_path))

        return X, y
